module top_module(
  input clk,
  input rst,
  output [m-1:0] out
);parameter n = 4; // number of states
parameter m = 2; // number of output signals

reg [n-1:0] current_state;
reg [m-1:0] out_reg;

// Define the output signals as functions of the current current_state
always @ (current_state) begin
  case (current_state)
    0: out_reg = {1'b0, 1'b0};
    1: out_reg = {1'b0, 1'b1};
    2: out_reg = {1'b1, 1'b0};
    3: out_reg = {1'b1, 1'b1};
  endcase
end

// Define the current_state transitions
always @ (posedge clk, posedge rst) begin
  if (rst) begin
    current_state <= 0;
  end else begin
    case (current_state)
      0: current_state <= 1;
      1: current_state <= 2;
      2: current_state <= 3;
      3: current_state <= 0;
    endcase
  end
end

// Assign the output signals
assign out = out_reg;

endmodule
